var findMissingElements = function(nums) {
    const present = new Set(nums);
    const lo = Math.min(...nums), hi = Math.max(...nums);
    const res = [];
    for (let v = lo; v <= hi; v++) if (!present.has(v)) res.push(v);
    return res;
};
